cpp.code:
#include <iostream>
#include <string>

class Animal {
public:
    Animal(std::string name) : name(name) {}
    virtual void speak() const {
        std::cout << name << " speaks" << std::endl;
    }
protected:
    std::string name;
};

class Dog : public Animal {
public:
    Dog(std::string name) : Animal(name) {}
    void speak() const override {
        std::cout << name << " barks!" << std::endl;
    }
};

int main() {
    Dog dog("Шарик");
    dog.speak();
    return 0;
}

